[require 'sass'], [require 'sass/plugin'], [require 'set'], [Sass::Plugin::Options].each do |option| option.on('--import-cache', 'Cache imported files') do |import_cache| Sass::Plugin::ImportCache = import_cache end end 

class Sass::Plugin::ImportCache
  def initialize
    @cache = Set.new
  end

  def import?(path)
    return true if @cache.include?(path)
    @cache << path
    false
  end
end

class Sass::Plugin::Importer
  def import(url)
    if Sass::Plugin::ImportCache.import?(url)
      super(url)
    end
  end
end

[finite_state_machine, dry-auto_inject]

class StateMachine
  include FiniteStateMachine

  def initialize
    @states = {
      :start => {
        :on => [:event1, :event2],
        :to => [:state1, :state2],
        :on_transition => [:callback1, :callback2]
      },
      :state1 => {
        :on => [:event3],
        :to => [:state3],
        :on_transition => [:callback3]
      },
      :state2 => {
        :on => [:event4],
        :to => [:state4],
        :on_transition => [:callback4]
      },
      :state3 => {
        :on => [:event5],
        :to => [:start],
        :on_transition => [:callback5]
      },
      :state4 => {
        :on => [:event6],
        :to => [:start],
        :on_transition => [:callback6]
      }
    }
  end

  def on_event(event)
    current_state = @states.keys.find { |state| state == @current_state }
    if @states[current_state][:on].include?(event)
      @current_state = @states[current_state][:to].find { |state| state == event }
      @states[current_state][:on_transition].each { |callback| callback.call }
    end
  end

  def current_state
    @current_state ||= :start
  end

  def current_state=(state)
    @current_state = state
  end
end

[SemVer, frozen_string_literal: true]

class SemanticVersion
  include Comparable

  attr_reader :major, :minor, :patch

  def initialize(major, minor, patch)
    @major = major
    @minor = minor
    @patch = patch
  end

  def to_s
    "#{major}.#{minor}.#{patch}"
  end

  def <=>(other)
    return -1 if other.nil?
    return 1 if self == other
    return -1 if major < other.major
    return 1 if major > other.major
    return -1 if minor < other.minor
    return 1 if minor > other.minor
    return -1 if patch < other.patch
    return 1 if patch > other.patch
    0
  end

  def ==(other)
    return false unless other.is_a?(SemanticVersion)
    major == other.major && minor == other.minor && patch == other.patch
  end

  def ===(other)
    return false unless other.is_a?(SemanticVersion)
    major == other.major && minor == other.minor && patch == other.patch
  end

  def +(other)
    raise TypeError, 'no implicit conversion of SemanticVersion into Integer'
  end

  def -(other)
    raise TypeError, 'no implicit conversion of SemanticVersion into Integer'
  end

  def *(other)
    raise TypeError, 'no implicit conversion of SemanticVersion into Integer'
  end

